 18→import com.pinterest.ktlint.rule.engine.core.api.editorconfig.EditorConfig
 19→import com.pinterest.ktlint.rule.engine.core.api.editorconfig.INDENT_SIZE_PROPERTY
 20→import com.pinterest.ktlint.rule.engine.core.api.editorconfig.INDENT_STYLE_PROPERTY
 21→import com.pinterest.ktlint.rule.engine.core.api.editorconfig.MAX_LINE_LENGTH_PROPERTY
 22→import com.pinterest.ktlint.rule.engine.core.api.firstChildLeafOrSelf
 23→import com.pinterest.ktlint.rule.engine.core.api.indent
 24→import com.pinterest.ktlint.rule.engine.core.api.isWhiteSpaceWithNewline
 25→import com.pinterest.ktlint.rule.engine.core.api.prevCodeLeaf
 26→import com.pinterest.ktlint.rule.engine.core.api.prevLeaf
 27→import com.pinterest.ktlint.rule.engine.core.api.prevSibling
 28→import com.pinterest.ktlint.rule.engine.core.api.upsertWhitespaceAfterMe
 29→import com.pinterest.ktlint.rule.engine.core.api.upsertWhitespaceBeforeMe
 30→import com.pinterest.ktlint.ruleset.standard.StandardRule
 31→import org.jetbrains.kotlin.com.intellij.lang.ASTNode
 32→import org.jetbrains.kotlin.com.intellij.psi.PsiWhiteSpace
 33→import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafPsiElement
 34→import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.PsiWhiteSpaceImpl
 35→import org.jetbrains.kotlin.psi.KtTypeArgumentList
 36→import org.jetbrains.kotlin.psi.psiUtil.children
 37→import org.jetbrains.kotlin.psi.psiUtil.collectDescendantsOfType
