        val code =
            """
            fun doSomething
            (
                paramA: String,
                paramB: String
            )
            """.trimIndent()
        val formattedCode =
            """
            fun doSomething(
                paramA: String,
                paramB: String
            )
            """.trimIndent()
        parameterListWrappingRuleAssertThat(code)
            .hasLintViolation(2, 1, """Unnecessary newline before "("""")
